def minCost(houses, cost, m, n, target):
    memo = {}
    def dfs(i, prev_col, hoods):
        if hoods > target: return float('inf')
        if i == m:
            return 0 if hoods == target else float('inf')
        if (i, prev_col, hoods) in memo:
            return memo[(i, prev_col, hoods)]
        res = float('inf')
        if houses[i] != 0:
            res = dfs(i + 1, houses[i], hoods + (1 if houses[i] != prev_col else 0))
        else:
            for c in range(1, n + 1):
                res = min(res, cost[i][c-1] + dfs(i + 1, c, hoods + (1 if c != prev_col else 0)))
        memo[(i, prev_col, hoods)] = res
        return res
    ans = dfs(0, 0, 0)
    return ans if ans != float('inf') else -1

